package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormatDefault;
    private CSVFormat csvFormatNoQuote;
    private CSVFormat csvFormatCustom;

    @BeforeEach
    public void setup() {
        csvFormatDefault = CSVFormat.DEFAULT;
        csvFormatNoQuote = CSVFormat.DEFAULT.withQuote((Character) null);
        csvFormatCustom = CSVFormat.newFormat(';').withQuote('\'').withQuoteMode(QuoteMode.ALL);
    }

    @Test
    public void testFormat_withNormalValues() {
        String result = csvFormatDefault.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    public void testFormat_withNullValue() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");
        String result = format.format("a", null, "c");
        assertEquals("a,NULL,c", result);
    }

    @Test
    public void testFormat_withEmptyValues() {
        String result = csvFormatDefault.format();
        assertEquals("", result);
    }

    @Test
    public void testFormat_withNoQuoteCharacter() {
        String result = csvFormatNoQuote.format("a,b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    public void testFormat_withCustomDelimiterAndQuote() {
        String result = csvFormatCustom.format("a;b", "b;c");
        // Values quoted due to QuoteMode.ALL and quote char '\''
        assertEquals("'a;b';'b;c'", result);
    }

    @Test
    public void testFormat_throwsIllegalStateExceptionOnIOException() throws Exception {
        // Create a CSVFormat instance proxy that throws IOException in format
        CSVFormat format = createCSVFormatProxyThrowingIOException(CSVFormat.DEFAULT);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            format.format("test");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("IO error", thrown.getCause().getMessage());
    }

    // Factory method to create a CSVFormat proxy instance that throws IOException in format()
    private CSVFormat createCSVFormatProxyThrowingIOException(CSVFormat delegate) throws Exception {
        // Use dynamic proxy or reflection-based subclassing is impossible because CSVFormat is final.
        // Instead, create a dynamic proxy that implements CSVFormat's interface is not possible (no interface).
        // So we create a wrapper class with the same API and delegate all calls except format().
        // For the test, we create an anonymous subclass of Object that mimics CSVFormat.format()

        return new CSVFormatWrapper(delegate);
    }

    // Wrapper class to simulate CSVFormat but override format to throw IOException wrapped in IllegalStateException
    private static class CSVFormatWrapper extends CSVFormat {
        private final CSVFormat delegate;

        CSVFormatWrapper(CSVFormat delegate) throws Exception {
            // Use reflection to create a new instance with the same fields as delegate
            super(getCharField(delegate, "delimiter"),
                  getCharacterField(delegate, "quoteCharacter"),
                  getQuoteModeField(delegate, "quoteMode"),
                  getCharacterField(delegate, "commentMarker"),
                  getCharacterField(delegate, "escapeCharacter"),
                  getBooleanField(delegate, "ignoreSurroundingSpaces"),
                  getBooleanField(delegate, "ignoreEmptyLines"),
                  getStringField(delegate, "recordSeparator"),
                  getStringField(delegate, "nullString"),
                  getObjectArrayField(delegate, "headerComments"),
                  getStringArrayField(delegate, "header"),
                  getBooleanField(delegate, "skipHeaderRecord"),
                  getBooleanField(delegate, "allowMissingColumnNames"),
                  getBooleanField(delegate, "ignoreHeaderCase"));
            this.delegate = delegate;
        }

        @Override
        public String format(final Object... values) {
            try {
                throw new IOException("IO error");
            } catch (IOException e) {
                throw new IllegalStateException(e);
            }
        }

        // Delegate other methods to the original CSVFormat instance as needed
        // For this test, we only override format(), so no need to override others

        // Reflection helpers to access private fields
        private static char getCharField(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return f.getChar(obj);
        }

        private static Character getCharacterField(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return (Character) f.get(obj);
        }

        private static QuoteMode getQuoteModeField(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return (QuoteMode) f.get(obj);
        }

        private static boolean getBooleanField(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return f.getBoolean(obj);
        }

        private static String getStringField(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return (String) f.get(obj);
        }

        private static Object[] getObjectArrayField(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return (Object[]) f.get(obj);
        }

        private static String[] getStringArrayField(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return (String[]) f.get(obj);
        }
    }
}
